152	    public synchronized boolean doCoredump(String filename) {
153	        if (!isReady())
154	            return false;
155	
156	        mCondition &= ~COREDUMPED;
157	        sendEvent(CODE_COREDUMP, filename, mCoredumpWork);
158	        return waitCore();
159	    }
